mapper.select:
SELECT * FROM comment 
WHERE post_id = #{postId}
ORDER BY created_at ASC

SELECT * FROM comment 
WHERE user_id = #{userId}
ORDER BY created_at DESC

SELECT * FROM comment 
WHERE parent_id = #{parentId}
ORDER BY created_at ASC

SELECT * FROM comment 
WHERE 1=1

    AND post_id = #{postId}


    AND user_id = #{userId}

ORDER BY created_at DESC

mapper.update:
UPDATE comment 
SET like_count = #{likeCount}
WHERE comment_id = #{commentId}

UPDATE comment 
SET like_count = like_count + 1
WHERE comment_id = #{commentId}

UPDATE comment 
SET like_count = GREATEST(like_count - 1, 0)
WHERE comment_id = #{commentId}

mapper.select:
SELECT * FROM comment 
WHERE post_id = #{postId}
ORDER BY like_count DESC, created_at DESC
LIMIT #{limit}

SELECT * FROM comment 
ORDER BY created_at DESC
LIMIT #{limit}

mapper.delete:
DELETE FROM comment 
WHERE comment_id = #{commentId} 
   OR parent_id = #{commentId}

mapper.select:
SELECT * FROM comment 
WHERE reply_to_user_id = #{replyToUserId}
ORDER BY created_at DESC
